document.getElementById('page-content').addEventListener('click', async event => {
  const button = event.target.closest && event.target.closest('#review-send');
  if (!button || button.dataset.preflightApproved === 'true' || state.sendPreflightRunning || state.fusionRunning) return;
  const address = document.getElementById('send-address')?.value.trim() || '';
  const amountText = document.getElementById('send-amount')?.value.trim() || '';
  const feeText = document.getElementById('send-fee')?.value.trim() || '';
  const paymentId = document.getElementById('send-payment-id')?.value.trim() || '';
  const mixin = Number(document.getElementById('send-mixin')?.value || 0);
  if (!/^RMBG[1-9A-HJ-NP-Za-km-z]{94}$/.test(address) || !/^\d+(?:\.\d{1,8})?$/.test(amountText) || !/^\d+(?:\.\d{1,8})?$/.test(feeText)) return;
  event.preventDefault(); event.stopImmediatePropagation(); state.sendPreflightRunning = true; button.disabled = true; button.textContent = 'Estimating transaction...';
  try {
    const request = { addresses: state.address ? [state.address] : [], transfers: [{ address, amount: String(mbgToAtomic(amountText)) }], changeAddress: state.address, fee: String(mbgToAtomic(feeText)), anonymity: mixin, unlockTime: '0' };
    if (paymentId) request.paymentId = paymentId;
    state.sendPreflight = await window.mbgWallet.preflightTransaction(request);
    if (state.sendPreflight.ok) { button.dataset.preflightApproved = 'true'; button.disabled = false; button.click(); }
    else { state.sendError = state.sendPreflight.message; render(); }
  } catch (error) { state.sendPreflight = { ok: false, recommendOptimize: false, message: `Preflight gagal: ${error.message}` }; state.sendError = state.sendPreflight.message; render(); }
  finally { state.sendPreflightRunning = false; }
}, true);
